from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Group clauses by subject to avoid repeating the subject many times
    from collections import defaultdict

    subject_clauses: dict[str, list[str]] = defaultdict(list)

    for t in triples:
        s = t.subject
        p = t.predicate
        o = _clean(t.object)

        # Build clause without repeating the subject (except for the first clause later)
        if p == "cityServed":
            clause = f"serves the city of {o}"
        elif p == "location":
            clause = f"is located in {o}"
        elif p == "country":
            clause = f"is in {o}"
        elif p == "isPartOf":
            clause = f"is part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            clause = f"lies at an elevation of {o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            clause = f"lies at an elevation of {o} feet above sea level"
        elif p == "operatingOrganisation":
            clause = f"is operated by {o}"
        elif p == "runwaySurfaceType":
            clause = f"has a runway surface of {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            clause = f"{idx.lower()} runway is {o} feet long"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            clause = f"{idx.lower()} runway is {o} metres long"
        elif p == "runwayName":
            clause = f"its runway is named {o}"
        elif p == "runwayLength":
            clause = f"its runway length is {o}"
        else:
            clause = f"has {p} {o}"

        subject_clauses[s].append(clause)

    # Assemble a fluent paragraph, using commas and 'and' for the last clause per subject
    sentences: list[str] = []
    for subj, clauses in subject_clauses.items():
        if not clauses:
            continue
        if len(clauses) == 1:
            sentences.append(f"{subj} {clauses[0]}.")
        else:
            # first clause keeps subject, remaining clauses are joined with commas, last preceded by 'and'
            first, *rest = clauses
            if len(rest) == 1:
                combined = f"{first} and {rest[0]}"
            else:
                combined = f"{first}, " + ", ".join(rest[:-1]) + f", and {rest[-1]}"
            sentences.append(f"{subj} {combined}.")

    # Join all subject sentences into one paragraph
    paragraph = " ".join(sentences)
    # Capitalise first character of the whole paragraph
    return paragraph[0].upper() + paragraph[1:] if paragraph else ""

# EVOLVE-BLOCK-END

